import { Component, computed, inject, OnDestroy } from '@angular/core';
import { LoaderService } from '../../../shared/loader/loader.service';
import { MatTableDataSource, MatTableModule } from '@angular/material/table';
import { MaUser } from './user-management.model';
import { MatDialog, MatDialogConfig } from '@angular/material/dialog';
import { SnackbarService } from '../../../shared/snack-bar/snack-bar.service';
import { UseManagementService } from './user-management.service';
import { CreateUserComponent } from '../../../components/create-user/create-user.component';
import { ConfirmationDialogComponent } from '../../../components/confirmation-dialog.component';
import { MatFormFieldModule, MatLabel } from '@angular/material/form-field';
import { MatInputModule } from '@angular/material/input';
import { MatIconModule } from '@angular/material/icon';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { LoaderComponent } from '../../../shared/loader/loader.component';
import { Subject } from 'rxjs';
import { debounceTime, distinctUntilChanged } from 'rxjs/operators';

@Component({
  selector: 'app-user-management',
  standalone: true,
  imports: [
    MatFormFieldModule, MatInputModule, MatIconModule,
    CommonModule, MatTableModule, MatLabel, FormsModule, LoaderComponent
  ],
  templateUrl: './user-management.component.html',
  styleUrl: './user-management.component.css'
})
export class UserManagementComponent implements OnDestroy {
  loader = inject(LoaderService);
  isLoading = computed(() => this.loader.loading());
  searchTerm: string = '';
  displayedColumns: string[] = ['Sl.No', 'Full Name', 'User Name', 'Role', 'Company', 'Email Address', 'MFA Enabled', 'status', 'Reset button', 'Action'];
  dataSource = new MatTableDataSource<MaUser>();

  currentPage = 1;
  pageSize = 20;
  totalCount = 0;
  allDataLoaded = false;
  private searchSubject = new Subject<string>();

  constructor(
    private dialog: MatDialog,
    private userService: UseManagementService,
    private snackBar: SnackbarService
  ) { }

  ngOnInit() {
    this.getMaUserDataFromDb(true);

    // Setup debounce for search
    this.searchSubject
      .pipe(
        debounceTime(1000)
      )
      .subscribe(() => {
        this.onSearch();
      });
  }

  ngOnDestroy() {
    this.searchSubject.complete();
  }

  inputSearch(): void {
    if (this.searchTerm.trim() === '') {
      this.onSearch();
    } else {
      this.searchSubject.next(this.searchTerm);
    }
  }

  // method to search the record globally
  onSearch(): void {
    this.getMaUserDataFromDb(true);
  }

  // method to  clear the search term
  clearSearch(): void {
    this.searchTerm = '';
    this.getMaUserDataFromDb(true);
  }

  // method to call the api on scroll
  onManualScroll(): void {
    const scrollContainer = document.querySelector('.table-container');
    if (scrollContainer) {
      const scrollPosition = scrollContainer.scrollTop + scrollContainer.clientHeight;
      const scrollHeight = scrollContainer.scrollHeight;

      if (
        scrollPosition >= scrollHeight - 10 &&
        !this.loader.loading() &&
        !this.allDataLoaded
      ) {
        this.getMaUserDataFromDb();
      }
    }
  }

  getMaUserDataFromDb(reset = false): void {
    if (reset) {
      this.currentPage = 1;
      this.allDataLoaded = false;
      this.dataSource.data = [];
      this.totalCount = 0;
    }

    const body = {
      page: this.currentPage,
      page_size: this.pageSize,
      query: this.searchTerm.trim(),
    };

    this.loader.show();

    this.userService.userDataFromDb(body).subscribe({
      next: (response: { data: MaUser[]; total_count: number }) => {
        const newData = response.data;
        this.totalCount = response.total_count;

        this.dataSource.data = [...this.dataSource.data, ...newData];

        if (this.dataSource.data.length >= this.totalCount) {
          this.allDataLoaded = true;
        }

        this.currentPage++;
        this.loader.hide();
      },
      error: () => {
        this.snackBar.showError("Something went wrong. Please try again later.");
        this.loader.hide();
      }
    });
  }

  openAddCargoDialog(): void {
    const dialogConfig = new MatDialogConfig();
    dialogConfig.position = { right: '0' };
    dialogConfig.height = '100%';
    dialogConfig.panelClass = ['animate__animated', 'animate__slideInRight'];

    const dialogRef = this.dialog.open(CreateUserComponent, dialogConfig);
    dialogRef.afterClosed().subscribe((result) => {
      if (result === 'refresh') {
        this.getMaUserDataFromDb(true);
      }
    });
  }

  openEditCargoDialog(rowData: MaUser): void {
    const dialogConfig = new MatDialogConfig();
    dialogConfig.position = { right: '0' };
    dialogConfig.height = '100%';
    dialogConfig.data = { rowData };
    dialogConfig.panelClass = ['animate__animated', 'animate__slideInRight'];

    const dialogRef = this.dialog.open(CreateUserComponent, dialogConfig);
    dialogRef.afterClosed().subscribe((result) => {
      if (result === 'refresh') {
        this.getMaUserDataFromDb(true);
      }
    });
  }

  resetPassword(username: string): void {
    const dialogRef = this.dialog.open(ConfirmationDialogComponent, {
      data: {
        header: 'Confirm Password Reset',
        text: `Are you sure you want to reset the password for user "${username}"?`
      }
    });

    dialogRef.afterClosed().subscribe((result) => {
      if (result === true) {
        this.loader.show();
        this.userService.resetUserPassword(username).subscribe({
          next: (response: any) => {
            this.loader.hide();
            this.snackBar.showSuccess(response.message || 'Password reset successfully');
          },
          error: (error) => {
            this.loader.hide();
            const errmsg = error.error?.detail || 'Failed to reset password. Please try again.';
            this.snackBar.showError(errmsg);
          }
        });
      }
    });
  }

}